local LMatchThreeGameBaseCtrl = LXImport(".LMatchThreeGameBaseCtrl")

---@class LMatchThreeGameHudCtrl:LMatchThreeGameBaseCtrl
local LMatchThreeGameHudCtrl  = LxClass("LMatchThreeGameHudCtrl", LMatchThreeGameBaseCtrl)
-----------------------------------------------------------------

local typeOfTextMesh          = typeof(CS.TextMeshPro)
local typeofCanvasGroup       = typeof(UnityEngine.CanvasGroup)
local Tweening                = DG.Tweening
local Color                   = Color
local Vector3                 = Vector3

-----------------------------------------------------------------
function LMatchThreeGameHudCtrl:LMatchThreeGameHudCtrl()
    self._index = 0
    self._seqMap = {}
end

-- 销毁
function LMatchThreeGameHudCtrl:OnDestroy()
    for k, tab in pairs(self._seqMap) do
        if tab.seq then
            tab.seq:Kill()
        end
        CS.DestroyObject(tab.obj)
    end
    self._seqMap = {}
end

-- 初始化
function LMatchThreeGameHudCtrl:Init()
    local root    = self:GetMap():GetMapTrans()
    self._parent  = CS.FindTrans(root, "LayerRoot/LayerHud")
    local trans   = CS.FindTrans(self._parent, "HudNode")
    self._nodeObj = trans.gameObject
end

-- 显示飘字
function LMatchThreeGameHudCtrl:ShowHud(pos, num, isRole, delayTime)
    self._index   = self._index + 1
    local index   = self._index

    local obj     = LxUnity.InstantObject(self._nodeObj)
    local trans   = obj.transform
    local hurtTxt = trans:GetComponentInChildren(typeOfTextMesh)
    trans:SetParent(self._parent, false)
    CS.ShowObject(trans, true)

    hurtTxt.text = num

    local color = hurtTxt.color
    color.a = 0
    hurtTxt.color = color
    trans.position = pos
    trans.localScale = Vector3(0.1, 0.1, 0.1)

    local tw1 = YXTween.TweenFloat(0, 1, 0.3, function(ival)
        hurtTxt.color = Color(color.r, color.g, color.b, ival)
    end)
    local tw2 = trans:DOScale(1.2, 0.3)
    local tw22 = trans:DOScale(1, 0.2)
    local tw3 = trans:DOMoveY(pos.y + 0.5, 1.5)
    local tw4 = YXTween.TweenFloat(1, 0, 1, function(ival)
        hurtTxt.color = Color(color.r, color.g, color.b, ival)
    end)

    delayTime = delayTime or 0
    local seq = Tweening.DOTween.Sequence()
    seq:Insert(delayTime, tw1)
    seq:Insert(delayTime, tw2)
    seq:Insert(delayTime + 0.3, tw22)
    seq:Insert(delayTime + 0.3, tw3)
    seq:Insert(delayTime + 1, tw4)
    seq:Play()
    seq:OnComplete(function()
        self._seqMap[index].seq = nil
    end)

    self._seqMap[index] = { obj = obj, seq = seq }

    gLGameAudio:PlaySoundByRefId(isRole and 363 or 362)
end

return LMatchThreeGameHudCtrl
